import{_ as s,o as i,c as t,a2 as a}from"./chunks/framework.DGp-bpT-.js";const u=JSON.parse('{"title":"Troubleshooting Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md"}'),n={name:"guide/troubleshooting.md"};function o(r,e,l,d,h,c){return i(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="troubleshooting-guide" tabindex="-1">Troubleshooting Guide <a class="header-anchor" href="#troubleshooting-guide" aria-label="Permalink to &quot;Troubleshooting Guide&quot;">​</a></h1><p>When errors happen, DSO is designed to fail securely rather than mask problems. This guide covers the most common issues and how to resolve them.</p><h2 id="common-issues" tabindex="-1">Common Issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to &quot;Common Issues&quot;">​</a></h2><h3 id="_1-installation-failures" tabindex="-1">1. Installation Failures <a class="header-anchor" href="#_1-installation-failures" aria-label="Permalink to &quot;1. Installation Failures&quot;">​</a></h3><p><strong>Symptom:</strong> <code>docker plugin install</code> hangs or returns <code>permission denied</code>.</p><p><strong>Resolution:</strong></p><ul><li>Ensure the Docker daemon is running (<code>systemctl status docker</code>).</li><li>The installation must be executed by a user in the <code>docker</code> group, or via <code>sudo</code>.</li><li>For the alternative shell-script install, ensure <code>curl</code> is installed and you are executing it with <code>sudo bash</code>.</li></ul><hr><h3 id="_2-provider-authentication-errors" tabindex="-1">2. Provider Authentication Errors <a class="header-anchor" href="#_2-provider-authentication-errors" aria-label="Permalink to &quot;2. Provider Authentication Errors&quot;">​</a></h3><p><strong>Symptom:</strong> You see errors like <code>failed fetching secret from aws: AccessDeniedException</code>.</p><p><strong>Resolution:</strong> The DSO provider cannot authenticate with your cloud provider.</p><ul><li><strong>AWS:</strong> Verify the instance profile has <code>secretsmanager:GetSecretValue</code> permissions for the specific secret ARN.</li><li><strong>Vault:</strong> Check if the passed <code>vault_token</code> in <code>dso.yaml</code> has expired or lacks the correct policy.</li><li><strong>Azure:</strong> Ensure the Managed Identity attached to the VM has &quot;Key Vault Secrets User&quot; permissions.</li></ul><p>Diagnostic command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Test connectivity manually</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dso</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aws</span></span></code></pre></div><hr><h3 id="_3-secret-not-found" tabindex="-1">3. Secret Not Found <a class="header-anchor" href="#_3-secret-not-found" aria-label="Permalink to &quot;3. Secret Not Found&quot;">​</a></h3><p><strong>Symptom:</strong> <code>vault secret myapp/db not found</code> or similar.</p><p><strong>Resolution:</strong> The authentication succeeded, but the secret name or path is incorrect.</p><ul><li>Ensure the spelling matches exactly.</li><li><strong>Azure:</strong> Key Vault paths use hyphens (<code>-</code>), not underscores (<code>_</code>).</li><li><strong>Vault:</strong> Ensure you are querying the correct mount path. KV v2 engines require <code>data/</code> in API calls (handled automatically if the mount path is correct).</li></ul><hr><h3 id="_4-container-fails-to-start" tabindex="-1">4. Container Fails to Start <a class="header-anchor" href="#_4-container-fails-to-start" aria-label="Permalink to &quot;4. Container Fails to Start&quot;">​</a></h3><p><strong>Symptom:</strong> Container exits immediately with <code>Missing required environment variable DB_PASSWORD</code>.</p><p><strong>Resolution:</strong></p><ul><li>Verify your <code>docker-compose.yml</code>. Did you set <code>DB_PASSWORD=</code> instead of just declaring <code>- DB_PASSWORD</code>? Setting an empty value overrides DSO&#39;s injection.</li><li>Run <code>docker dso inspect &lt;container-id&gt;</code> to see if DSO injected the expected values.</li></ul><hr><h3 id="_5-rotation-not-working" tabindex="-1">5. Rotation Not Working <a class="header-anchor" href="#_5-rotation-not-working" aria-label="Permalink to &quot;5. Rotation Not Working&quot;">​</a></h3><p><strong>Symptom:</strong> The secret changes in Vault, but the container doesn&#39;t get updated.</p><p><strong>Resolution:</strong></p><ul><li>Ensure <code>rotation: true</code> is set for the secret mapping in <code>dso.yaml</code>.</li><li>Ensure the <code>agent.watch.mode</code> is set correctly. If using polling, check <code>polling_interval</code>.</li><li>Look for debouncer messages. If the secret was updated multiple times rapidly, DSO debounces the changes for 30 seconds before acting.</li><li>If using <code>reload_strategy: signal</code>, verify the container application actually implements a <code>SIGHUP</code> reload routine.</li></ul><hr><h3 id="_6-permission-denied-errors" tabindex="-1">6. Permission Denied Errors <a class="header-anchor" href="#_6-permission-denied-errors" aria-label="Permalink to &quot;6. Permission Denied Errors&quot;">​</a></h3><p><strong>Symptom:</strong> Error reading <code>/var/run/dso.sock</code>.</p><p><strong>Resolution:</strong> The CLI plugin cannot communicate with the agent daemon. Check the DSO daemon status:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dso</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dso</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span></span></code></pre></div><p>Ensure the socket file exists and is writable by the docker group.</p><h2 id="diagnostic-commands" tabindex="-1">Diagnostic Commands <a class="header-anchor" href="#diagnostic-commands" aria-label="Permalink to &quot;Diagnostic Commands&quot;">​</a></h2><p>DSO includes several built-in commands to help you identify problems.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Verify the dso.yaml syntax and configuration schema is valid</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dso</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> validate</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Inspect exactly what environments are exported to a running container</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dso</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> inspect</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">container-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run a dry-run composed deployment to see what will happen</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dso</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span></span></code></pre></div>`,38)])])}const g=s(n,[["render",o]]);export{u as __pageData,g as default};
